var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그래서.","JPN":"それで、","ENG":"So...","TWN":"所以……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"요약하면 아무것도 건진 게 없다는 거네.","JPN":"要するに何もゲットできなかったってわけね。","ENG":"Basically we got nothing.","TWN":"簡單來說，就是什麼都沒得到。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......한심하군요.","JPN":"情けないですね。","ENG":"How pathetic.","TWN":"……真是丟臉呢。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"지금 이런 어이없는 보고를 듣기 위해 제 소중한 시간을 13시간 36분 24초나 허비한 건가요?","JPN":"こんなしょうもない報告を聞くために、僕の大事な時間を13時間36分24秒も無駄にしてしまったと。","ENG":"Did I just waste 13 hours 36 minutes and 24 seconds of my time to hear out this ridiculous briefing?","TWN":"為了聽這個荒唐的報告，浪費了我寶貴時間的13個小時36分鐘24秒嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"누차 말씀드리지만 우리가 사용하는 무기, 탄약은 물론 팬티 한 장까지 모두 귀중한 국민의 세금으로 주어진 것입니다.","JPN":"何度も言いますが、我々が使用する兵器、弾薬はもとより、\\nパンツ一枚まで、すべて貴重な国民の税金で賄っているのです。","ENG":"As I always say, every weapon, bullet, and even your underwear are paid for by precious taxpayers’ money.","TWN":"我說過很多次了，我們用的武器、彈藥，甚至是任何一條內褲，都是人民繳納的寶貴稅金。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......팬티는 내 돈으로 사는데.","JPN":"……パンツは自分のお金で買ってるけどね。","ENG":"Well, I buy my own underwear...","TWN":"……內褲我是花自己的錢買的啊。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그 돈은 어디에서 나온다고 생각합니까?","JPN":"そのお金はどこから出てると思いますか。","ENG":"And where do you get the money to do that?","TWN":"那妳有想過妳的錢是從哪裡來的嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"국민의 세금으로 급여를 받는 우리가, 특히나 이런 비상시국에 시간을 낭비한다는 것은 직무태만을 넘어 반국가적 행위일 수도 있습니다.","JPN":"国税から給与をもらっている僕たちが、特にこのような非常時に時間を無駄にすることは\\n職務怠慢を通り越し、反国家的行為になりかねません。","ENG":"The taxpayers pay our salary. Wasting time in an emergency like this not only constitutes loafing but perhaps even an act of treason.","TWN":"拿人民納的稅當薪水的我們，在這種危急時刻卻在浪費時間，這根本已經超越怠忽職守的等級了，這是叛國行為。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아니, 무슨 비행기 타고 오는데 반국가적 행위씩이나......","JPN":"そんな。飛行機で移動したくらいで反国家的な行為だなんて、言いすぎじゃ……","ENG":"All we did was take a plane... What treason?","TWN":"不是，我們是坐什麼飛機來的，竟然還成了叛國行為……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"실비아 씨의 안일한 생각에 놀라움을 금할 수 없군요.","JPN":"シルビアさんの安易な考えには驚きしかありません。","ENG":"I am appalled by your lax attitude toward this whole affair.","TWN":"像希爾維亞小姐這種不知進取的想法，真令人無法不感到驚訝。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"지금도 각 지역의 로스트 쉽에 대응하느라 예비 전력까지 모두 동원하고 있는 상황입니다.","JPN":"今なお、各地域のロストシップに対応するために、\\n予備電力までフルで使っている状況です。","ENG":"Even as we speak, the reserves are being mobilized to respond to the Lost Ship situation across the world.","TWN":"現在為了對付各地區的失落艦船，我們連預備兵力都出動了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"저와 실비아 씨 같은 고등급 카운터가 왕복 30시간이 넘게 빠지게 되면, 그 빈자리를 누가 채울 거라고 생각합니까?","JPN":"僕とシルビアさんのようなハイレベルのカウンターが往復30時間以上も抜けたら、\\nその穴埋めは誰がすると？","ENG":"If high grade Counters like you and I become unavailable for over 30 hours, who’s going to fill in for us?","TWN":"像我和希爾維亞小姐這樣的高等制裁者，如果在往返過程中超過30分鐘，妳覺得要誰來補上這段時間的空缺？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"훈련도 덜 된 저등급 카운터나 일반 부대가 나설 수밖에 없죠.","JPN":"訓練も十分にできていない低ランクカウンターや一般部隊しかいないですよね。","ENG":"It’ll be less experienced, lower grade Counters or ordinary, non-powered troopers.","TWN":"只有派出沒受過什麼訓練的低等制裁者，和一般部隊了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"결국 불필요한 손실이 발생하고, 그 손실은 고스란히 국가의 피해로 누적될 것입니다.","JPN":"結局、無駄な損失が発生し、その損失はそのまま国の損害として溜まるのです。","ENG":"This will in turn lead to unnecessary losses, which will ultimately impact the nation.","TWN":"最後，這種情況只會產生沒必要的損失，這些損失又都成了國家的損失。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그렇지 않습니까?","JPN":"そう思いませんか？","ENG":"Am I wrong?","TWN":"沒錯吧？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아니...... 그건...... 그렇긴 한데......","JPN":"いや……それは……そうだけど……","ENG":"No... Well... I guess you've got a point, but...","TWN":"不……那個……是那樣沒錯，但是……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그 실비아 양을 이 정도로 쩔쩔매게 만들 수 있는 분이 있다니.","JPN":"あのシルビアさんを、ここまで困惑させる方がいるなんて。","ENG":"Wow, so there’s someone who can make even Sylvia nervous, huh?","TWN":"沒想到是個能讓希爾維亞小姐手足無措的人。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이것 참 놀랍군요.","JPN":"これは驚きですね。","ENG":"I’m impressed.","TWN":"真是令人驚訝呢。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};